#!/usr/bin/env bash
set -euo pipefail
ROOT="$(cd "$(dirname "$0")" && pwd)/build"
SDK="$ROOT/wasi-sdk"; SR="$SDK/share/wasi-sysroot"; Z="$ROOT/z88dk"; SCC="$Z/src/sccz80"
OUT="$ROOT/obj-sccz80"; mkdir -p "$OUT"
CC="$SDK/bin/clang"
WASI="--sysroot=$SR -D_WASI_EMULATED_SIGNAL -D_WASI_EMULATED_PROCESS_CLOCKS -D_WASI_EMULATED_GETPID -D_WASI_EMULATED_MMAN"
INC="-I. -I../common -I../../ext/uthash/src"
# config.h already generated by build-z80asm.sh; regenerate if missing
[ -f "$Z/src/config.h" ] || cat > "$Z/src/config.h" <<CFG
#define PREFIX "/z88dk"
#define BINDIR "/z88dk/bin"
#define UNIX 1
#define Z88DK_VERSION "wasi-spike"
CFG
cd "$SCC"
objs=()
for f in callfunc cdbfile codegen const data declinit error expr goto io lex main misc plunge preproc primary stmt sym while declparse; do
  o="$OUT/$f.o"
  $CC -std=gnu99 -O2 $WASI $INC -c "$f.c" -o "$o"
  objs+=("$o")
done
$CC -std=gnu99 -O2 $WASI $INC -c ../common/option.c -o "$OUT/option.o"; objs+=("$OUT/option.o")
so="$OUT/wasm-stubs.o"; $CC -std=gnu99 -O2 $WASI -c "$ROOT/wasm-stubs.c" -o "$so"; objs+=("$so")
$CC $WASI "${objs[@]}" -lwasi-emulated-signal -lwasi-emulated-process-clocks -lwasi-emulated-getpid -lwasi-emulated-mman -o "$ROOT/sccz80.wasm"
ls -lh "$ROOT/sccz80.wasm"; file "$ROOT/sccz80.wasm"
